// Recalculate TotalFlow, LnF, LnPxLnF, LnF2 for every header row
// using the updated density values
ForAll(
    col_PressureReadings_Header As hdr,
    With(
        {
            wfx_Density: If(
                cVar_TestMetaData.PressDepress = "Pressurisation",
                varInternalDensityValue,
                varExternalDensityValue
            ),
            wfx_AvgFanFlow: IfError(
                Average(
                    Filter(
                        col_PressureReadings,
                        Value         = hdr.Value &&
                        SetNumber     = hdr.SetNumber &&
                        ManometerType = "Fan" &&
                        !IsBlank(PressurePointFanFlow)
                    ),
                    PressurePointFanFlow
                ),
                Blank()
            )
        },
        With(
            {
                wfx_TotalFlow: IfError(
                    If(
                        hdr.ActiveCalculation = false || IsBlank(wfx_AvgFanFlow) || wfx_AvgFanFlow = 0,
                        Blank(),
                        wfx_AvgFanFlow * 3600 * 1.2 / wfx_Density
                    ),
                    Blank()
                )
            },
            With(
                {
                    wfx_LnP: IfError(If(hdr.AvgBuildPa <> 0, Ln(Abs(hdr.AvgBuildPa)), Blank()), Blank()),
                    wfx_LnF: IfError(If(wfx_TotalFlow > 0, Ln(wfx_TotalFlow), Blank()), Blank())
                },
                Patch(
                    col_PressureReadings_Header,
                    hdr,
                    {
                        TotalFlow: wfx_TotalFlow,
                        LnF:       wfx_LnF,
                        LnPxLnF:   IfError(wfx_LnP * wfx_LnF, Blank()),
                        LnF2:      IfError(wfx_LnF ^ 2,        Blank())
                    }
                )
            )
