                    Table(
                        {Value:"ATTMA TSL1: V3 2016", RelativeHumidity: 0.5},
                        {Value:"ATTMA TSL1: V4 2021", RelativeHumidity: 0.5},
                        {Value:"ATTMA TSL3: V1 2021", RelativeHumidity: 0.5},
                        {Value:"ATTMA TSL2: V1 2010", RelativeHumidity: 0.5},
                        {Value:"ATTMA TSL2: V2 2021", RelativeHumidity: 0.5},
                        {Value:"ATTMA TSL4: V1 2018", RelativeHumidity: 0.5},
                        {Value:"ATTMA TSL4: V2 2021", RelativeHumidity: 0.5},
                        {Value:"CIBSE TM23 2000",     RelativeHumidity: 0},
                        {Value:"CIBSE TM23 2022",     RelativeHumidity: 0}
                    ),
                    Value = Text(varTestInfo.TestStandard)
                ).RelativeHumidity,
                0
            )
        );
        Set(varMeta_TestType,         Text(wthMeta.TestType));
        Set(varMeta_Engineer,         Text(wthMeta.Engineer));
        Set(varMeta_EngineerLocation, Text(wthMeta.EngineerLocation));
