    "Differential Pressures",
    With(
        { wthMeta: LookUp(col_TestRun, TestID = varSelectedTestRunID).TestMetaData },
        Set(varSelectedTestRun,       LookUp(col_TestRun, TestID = varSelectedTestRunID));
        Set(varMeta_TestType,         Text(wthMeta.TestType));
        Set(varMeta_Engineer,         Text(wthMeta.Engineer));
        Set(varMeta_EngineerLocation, Text(wthMeta.EngineerLocation));
        Set(varMeta_OpeningTargetPA,  Text(wthMeta.OpeningTargetPA));
        Set(varMeta_ClosingTargetPA,  Text(wthMeta.ClosingTargetPA));
        Set(varMeta_PressureStep,     Text(wthMeta.PressureStep));
        Set(varMeta_TargetPoints,     Text(wthMeta.TargetPoints));
        Set(varMeta_DateTimeTest,     Text(wthMeta.DateTimeTest))
    ),

    "Pre-Test",
    With(
        { wthTestRun: LookUp(col_TestRun, TestNo = varSelectedTestNo) },
        Set(varSelectedTestRun, wthTestRun);

        Clear(col_FanOffPressures);
        Clear(col_FanOffPressures_Display);

        If(
            IsBlank(wthTestRun.PreTestData) || IsEmpty(wthTestRun.PreTestData.FanOffPressures),
            ClearCollect(
                col_FanOffPressures,
                Ungroup(
                    ForAll(
                        Filter(
                            col_EquipmentLocationsItems,
                            Selected = true &&
                            EquipmentType = "Manometer" &&
                            ManometerType = "Build" &&
                            !IsBlank(SetLocationRef)
                        ) As manometer,
                        ForAll(
                            Sequence(10),
                            {
                                SerialNumber:   manometer.SerialNumber,
                                ReadingNo:      Value(ThisRecord.Value),
                                RawInput:       0,
                                CorrectedInput: 0,
                                CalibScaler:    LookUp(col_Manometer, GaugeReference = manometer.SerialNumber).Scaler,
                                CalibConst:     LookUp(col_Manometer, GaugeReference = manometer.SerialNumber).Const
                            }
                        )
                    ),
                    Value
                )
            ),
            ClearCollect(
                col_FanOffPressures,
                ForAll(
                    wthTestRun.PreTestData.FanOffPressures As rec,
                    {
                        SerialNumber:   Text(rec.SerialNumber),
                        ReadingNo:      Value(rec.ReadingNo),
                        RawInput:       Value(rec.RawInput),
                        CorrectedInput: Value(rec.CorrectedInput),
                        CalibScaler:    Value(rec.CalibScaler),
                        CalibConst:     Value(rec.CalibConst)
                    }
                )
            )
        );

        ClearCollect(col_FanOffPressures_Display, col_FanOffPressures)
    ),

    "Post-Test",
    With(
        { wthTestRun: LookUp(col_TestRun, TestNo = varSelectedTestNo) },
        Set(varSelectedTestRun, wthTestRun);

        Clear(col_FanOffPressuresPost);
        Clear(col_FanOffPressures_DisplayPost);

        If(
            IsBlank(wthTestRun.PostTestData) || IsEmpty(wthTestRun.PostTestData.FanOffPressures),
            ClearCollect(
                col_FanOffPressuresPost,
                Ungroup(
                    ForAll(
                        Filter(
                            col_EquipmentLocationsItems,
                            Selected = true &&
                            EquipmentType = "Manometer" &&
                            ManometerType = "Build" &&
                            !IsBlank(SetLocationRef)
                        ) As manometer,
                        ForAll(
                            Sequence(10),
                            {
                                SerialNumber:   manometer.SerialNumber,
                                ReadingNo:      Value(ThisRecord.Value),
                                RawInput:       0,
                                CorrectedInput: 0,
                                CalibScaler:    LookUp(col_Manometer, GaugeReference = manometer.SerialNumber).Scaler,
                                CalibConst:     LookUp(col_Manometer, GaugeReference = manometer.SerialNumber).Const
                            }
                        )
                    ),
                    Value
                )
            ),
            ClearCollect(
                col_FanOffPressuresPost,
                ForAll(
                    wthTestRun.PostTestData.FanOffPressures As rec,
                    {
                        SerialNumber:   Text(rec.SerialNumber),
                        ReadingNo:      Value(rec.ReadingNo),
                        RawInput:       Value(rec.RawInput),
                        CorrectedInput: Value(rec.CorrectedInput),
                        CalibScaler:    Value(rec.CalibScaler),
                        CalibConst:     Value(rec.CalibConst)
                    }
                )
            )
        );

        ClearCollect(col_FanOffPressures_DisplayPost, col_FanOffPressuresPost)
    )
)
